        "id": 1,
        "device": "router2",
        "action": "add_static_route",
        "target": "192.168.0.0/24",
        "parameters": [
          "next-hop 10.0.0.1",
          "description route-to-192.168.0.0/24-via-R1"
        ]
      }
    ]
  }
}

